import React, { useState } from 'react';
import './index.css';
import { Shield, ShieldAlert, ShieldCheck, Search } from 'lucide-react';

function App() {
  const [query, setQuery] = useState("");
  const [status, setStatus] = useState("idle"); // idle, scanning, exposed, secure

  const handleScan = async () => {
    if (!query) return;
    setStatus("scanning");
    
    try {
      const response = await fetch(`http://localhost:8000/add-to-watchlist${query}`);
      const data = await response.json();
      
      // Simulate a small delay for "Security Analysis" feel
      setTimeout(() => {
        if (data.status === "EXPOSED") setStatus("exposed");
        else setStatus("secure");
      }, 1500);
    } catch (error) {
      console.error("Backend offline!");
      setStatus("idle");
      alert("BACKEND OFFLINE: Please start your Python server.");
    }
  };

  return (
    <div className="min-h-screen p-10">
      {status === "scanning" && <div className="scanning-bar"></div>}
      
      <header className="mb-10 border-b border-green-900 pb-4 flex justify-between items-center">
        <h1>SHIELD // DATA_EXPOSURE_MONITOR_v1.0</h1>
        <div className="text-xs opacity-50">STatus: {status.toUpperCase()}</div>
      </header>

      <main className="flex flex-col items-center justify-center mt-20">
        <div className="relative w-full max-w-xl">
          <input 
            type="text" 
            placeholder="ENTER AADHAAR / PAN / EMAIL..." 
            className="w-full"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
          />
          <button 
            onClick={handleScan}
            className="mt-6 w-full flex items-center justify-center gap-2"
          >
            <Search size={18} /> INITIALIZE_DEEP_SCAN
          </button>
        </div>

        <div className="mt-20 text-center">
          {status === "idle" && <Shield size={80} className="opacity-20 mx-auto" />}
          {status === "scanning" && <div className="animate-pulse">ANALYZING ENCRYPTED DUMPS...</div>}
          
          {status === "exposed" && (
            <div className="text-red-500 animate-bounce">
              <ShieldAlert size={80} className="mx-auto mb-4" />
              <h2 className="text-2xl font-bold">WARNING: IDENTITY EXPOSED</h2>
              <p className="mt-2 opacity-70">MATCH FOUND IN KNOWN DARK WEB BREACH.</p>
            </div>
          )}

          {status === "secure" && (
            <div className="text-blue-400">
              <ShieldCheck size={80} className="mx-auto mb-4" />
              <h2 className="text-2xl font-bold">IDENTITY SECURE</h2>
              <p className="mt-2 opacity-70">NO HASH MATCHES FOUND IN CURRENT DATABASE.</p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

export default App;
